-- Program: Deadlift Mobility Prep
-- Category: Lift Mobility -> mobility
-- Priority: High
-- Durations: [1, 2, 4], Sessions: [3, 4]

-- Insert branded program
INSERT INTO branded_programs (
    name, description, category, difficulty_level,
    duration_weeks, sessions_per_week, split_type,
    goals, requires_gym, is_active
) VALUES (
    'Deadlift Mobility Prep',
    'Pre-deadlift mobility drills targeting hip hinge, thoracic spine, and hamstring flexibility',
    'mobility',
    'all_levels',
    4,
    4,
    'flow',
    ARRAY['Increase maximal strength', 'Progressive overload', 'Improve flexibility', 'Enhance body awareness']::text[],
    true,
    true
) ON CONFLICT (name) DO UPDATE SET
    description = EXCLUDED.description,
    category = EXCLUDED.category,
    difficulty_level = EXCLUDED.difficulty_level,
    duration_weeks = EXCLUDED.duration_weeks,
    sessions_per_week = EXCLUDED.sessions_per_week,
    split_type = EXCLUDED.split_type,
    goals = EXCLUDED.goals,
    requires_gym = EXCLUDED.requires_gym,
    updated_at = NOW();

-- Variant: Deadlift Mobility Prep - 1w 3x/wk
INSERT INTO program_variants (
    base_program_id,
    intensity_level,
    duration_weeks,
    variant_name,
    program_category,
    sessions_per_week,
    session_duration_minutes,
    goals,
    workouts
) SELECT
    bp.id,
    'Medium',
    1,
    'Deadlift Mobility Prep - 1w 3x/wk',
    'mobility',
    3,
    60,
    ARRAY['Increase maximal strength', 'Progressive overload', 'Improve flexibility', 'Enhance body awareness']::text[],
    '[]'::jsonb
FROM branded_programs bp
WHERE bp.name = 'Deadlift Mobility Prep'
ON CONFLICT DO NOTHING;

INSERT INTO program_variant_weeks (
    variant_id, week_number, phase, focus, workouts,
    program_name, variant_name, priority, has_supersets, description, category
) SELECT
    pv.id,
    1,
    'Single Session',
    'Week 1 - Build',
    '[{"workout_name": "Deadlift Mobility Prep", "type": "flexibility", "duration_minutes": 20, "exercises": [{"name": "Foam Roll Thoracic Spine", "exercise_library_id": null, "in_library": false, "sets": 2, "reps": 10, "rest_seconds": 0, "weight_guidance": "Slow passes", "equipment": "Foam Roller", "body_part": "Back", "primary_muscle": "Thoracic Spine", "secondary_muscles": ["Erector Spinae"], "difficulty": "beginner", "form_cue": "Roll from mid-back to upper back, pause on tight spots", "substitution": "Lacrosse Ball T-Spine"}, {"name": "Banded Hip Distraction", "exercise_library_id": null, "in_library": false, "sets": 2, "reps": 1, "rest_seconds": 0, "weight_guidance": "Hold 45s each side", "equipment": "Resistance Band", "body_part": "Hips", "primary_muscle": "Hip Flexors", "secondary_muscles": ["Glutes"], "difficulty": "beginner", "form_cue": "Anchor band at hip crease, rock forward and back", "substitution": "Hip Flexor Stretch"}, {"name": "90/90 Hip Switch", "exercise_library_id": null, "in_library": false, "sets": 2, "reps": 8, "rest_seconds": 0, "weight_guidance": "Controlled tempo", "equipment": "Bodyweight", "body_part": "Hips", "primary_muscle": "Gluteus Medius", "secondary_muscles": ["Hip Flexors", "Adductors"], "difficulty": "beginner", "form_cue": "Keep tall spine, switch smoothly", "substitution": "Seated Hip Rotation"}, {"name": "Cat-Cow", "exercise_library_id": null, "in_library": false, "sets": 2, "reps": 10, "rest_seconds": 0, "weight_guidance": "Flow with breath", "equipment": "Bodyweight", "body_part": "Back", "primary_muscle": "Erector Spinae", "secondary_muscles": ["Core"], "difficulty": "beginner", "form_cue": "Inhale arch, exhale round", "substitution": "Seated Cat-Cow"}, {"name": "Kettlebell Prying Goblet Squat", "exercise_library_id": null, "in_library": false, "sets": 2, "reps": 8, "rest_seconds": 0, "weight_guidance": "Light weight", "equipment": "Kettlebell", "body_part": "Hips", "primary_muscle": "Adductors", "secondary_muscles": ["Hip Flexors"], "difficulty": "intermediate", "form_cue": "Hold bottom position, use elbows to push knees out", "substitution": "Bodyweight Deep Squat Hold"}, {"name": "Single-Leg Romanian Deadlift Hold", "exercise_library_id": null, "in_library": false, "sets": 2, "reps": 1, "rest_seconds": 0, "weight_guidance": "Hold 30s each side", "equipment": "Bodyweight", "body_part": "Legs", "primary_muscle": "Hamstrings", "secondary_muscles": ["Glutes", "Lower Back"], "difficulty": "beginner", "form_cue": "Maintain neutral spine, slight knee bend", "substitution": "Standing Hamstring Stretch"}]}]'::jsonb,
    'Deadlift Mobility Prep',
    'Deadlift Mobility Prep - 1w 3x/wk',
    'High',
    false,
    'Pre-deadlift mobility drills targeting hip hinge, thoracic spine, and hamstring flexibility',
    'Lift Mobility'
FROM program_variants pv
JOIN branded_programs bp ON bp.id = pv.base_program_id
WHERE bp.name = 'Deadlift Mobility Prep'
  AND pv.duration_weeks = 1
  AND pv.sessions_per_week = 3
ON CONFLICT DO NOTHING;

